  1→// Headless game simulation - no DOM, no animation
  2→// Used by MCTS/RL hint systems to evaluate moves
  3→
  4→import { applyGravity } from "./gravity.js";
  5→import { findMatches } from "./match-detector.js";
  6→import { processMerges, calculateMiddlePositions } from "./merge-processor.js";
  7→import { getDisplayValue } from "./tile-helpers.js";
  8→
  9→/**
 10→ * Deep-clone an individual tile, including nested objects.
 11→ */
 12→function cloneTile(tile) {
 13→    if (!tile) return null;
 14→    const cloned = { ...tile };
 15→    if (tile.rectAnchor && typeof tile.rectAnchor === "object") {
 16→        cloned.rectAnchor = { ...tile.rectAnchor };
 17→    }
 18→    if (tile.cellMergeCounts && typeof tile.cellMergeCounts === "object") {
 19→        cloned.cellMergeCounts = { ...tile.cellMergeCounts };
 20→    }
 21→    return cloned;
 22→}
 23→
 24→/**
 25→ * Deep-clone the board (2D array of tile objects).
 26→ */
 27→function cloneBoard(board) {
 28→    return board.map((row) => row.map((tile) => cloneTile(tile)));
 29→}
 30→
 31→/**
 32→ * Create a minimal game-like context for headless simulation.
 33→ * Copies only the fields needed by findMatches, processMerges, applyGravity.
 34→ */
 35→function createSimContext(game, board) {
 36→    return {
 37→        board,
 38→        boardWidth: game.boardWidth,
 39→        boardHeight: game.boardHeight,
 40→        tileValues: game.tileValues,
 41→        spawnableTileValues: game.spawnableTileValues,
 42→        specialTileConfig: game.specialTileConfig,
 43→        levelGoals: game.levelGoals.map((g) => ({ ...g })),
 44→        allowNonMatchingSwaps: false,
 45→        activePowerUp: null,
 46→        isUserSwap: false,
 47→        lastSwapPosition: null,
 48→        movesUsed: game.movesUsed,
 49→        maxMoves: game.maxMoves,
 50→        score: 0,
 51→        animating: false,
 52→        pendingTileLevelShift: false,
 53→        cursedTileCreatedCount: { ...game.cursedTileCreatedCount },
 54→        cursedTileCreatedThisTurn: {},
 55→        shouldDecrementCursedTimers: false,
 56→        matchStats: {
 57→            tFormationCount: 0, lFormationCount: 0, blockFormationCount: 0,
 58→            match5Count: 0, match4Count: 0, match3Count: 0,
 59→        },
 60→
 61→        // Methods called by processMerges/createMergedTiles
 62→        findMatches() { return findMatches(this); },
 63→        hasMatchesForSwap(r1, c1, r2, c2) {
 64→            // Used internally - check if swap creates a match at those positions
 65→            const matches = findMatches(this);
 66→            return matches.some((match) =>
 67→                match.tiles.some((t) =>
 68→                    (t.row === r1 && t.col === c1) || (t.row === r2 && t.col === c2)
 69→                )
 70→            );
 71→        },
 72→        saveScore() {},
 73→        updateGoalDisplay() {},
 74→        updateMovesDisplay() {},
 75→        renderBoard() {},
 76→        dropGems() {},
 77→        checkAndShiftTileLevels() {},
 78→        shiftTileLevels() { return Promise.resolve(); },
 79→        checkAndGrantPowerUpReward() {},
 80→        grantFormationPowerUp() {},
 81→    };
 82→}
 83→
 84→/**
 85→ * Accumulate goal progress for a given tile value, filtering to "created" goals only.
 86→ */
 87→function accumulateGoal(goalProgress, levelGoals, tileValue, count) {
 88→    const hasGoal = levelGoals.some((g) => g.goalType === "created" && g.tileValue === tileValue);
 89→    if (hasGoal) {
 90→        goalProgress[tileValue] = (goalProgress[tileValue] || 0) + count;
 91→    }
 92→}
 93→
 94→/**
 95→ * Simulate a single complete move (swap → match → merge → gravity cascade).
 96→ *
 97→ * @param {Match3Game} game - Live game instance (not mutated)
 98→ * @param {{ row1: number, col1: number, row2: number, col2: number }} swap
 99→ * @returns {{
100→ *   valid: boolean,
101→ *   newBoard: Array[][],
102→ *   scoreDelta: number,
103→ *   goalProgress: Object,
104→ *   cascades: number
105→ * }}
106→ */
107→export function simulateMove(game, swap) {
108→    const { row1, col1, row2, col2 } = swap;
109→
110→    const board = cloneBoard(game.board);
111→    const ctx = createSimContext(game, board);
112→
113→    // Swap tiles on the board
114→    const temp = ctx.board[row1][col1];
115→    ctx.board[row1][col1] = ctx.board[row2][col2];
116→    ctx.board[row2][col2] = temp;
117→
118→    ctx.lastSwapPosition = { row: row2, col: col2, movedFrom: { row: row1, col: col1 } };
119→    ctx.isUserSwap = true;
120→
121→    // Verify swap creates a match
122→    const initialMatches = findMatches(ctx);
123→    const hasMatch = initialMatches.some((match) =>
124→        match.tiles.some((t) =>
125→            (t.row === row1 && t.col === col1) || (t.row === row2 && t.col === col2)
126→        )
127→    );
128→
129→    if (!hasMatch) {
130→        // Revert and return invalid
131→        ctx.board[row2][col2] = ctx.board[row1][col1];
132→        ctx.board[row1][col1] = temp;
133→        return { valid: false, newBoard: ctx.board, scoreDelta: 0, goalProgress: {}, cascades: 0 };
134→    }
135→
136→    let scoreDelta = 0;
137→    const goalProgress = {};
138→    let cascades = 0;
139→    const maxCascades = 20;
140→
141→    // Cascade loop: find matches → merge → gravity → repeat
142→    let isFirstIteration = true;
143→    while (cascades < maxCascades) {
144→        ctx.isUserSwap = isFirstIteration;
145→
146→        const matchGroups = findMatches(ctx);
147→        if (matchGroups.length === 0) break;
148→
149→        // Accumulate score
150→        matchGroups.forEach((group) => {
151→            const displayValue = getDisplayValue(group.value);
152→            scoreDelta += displayValue * group.tiles.length;
153→        });
154→
155→        // Track goal progress — mirrors createMergedTiles logic in merge-processor.js
156→        matchGroups.forEach((group) => {
157→            const isTLFormation = group.direction === "T-formation" || group.direction === "L-formation";
158→            const is5LineFormation = group.direction === "line_5_horizontal" || group.direction === "line_5_vertical";
159→            const valueIncrement = isTLFormation || is5LineFormation ? 2 : 1;
160→            const mergedValue = group.value + valueIncrement;
161→
162→            // Count how many merged tiles are produced (1 for T/L/5-line, 2 for 4-tile line/block)
163→            const positions = isTLFormation ? [group.intersection] : calculateMiddlePositions(ctx, group.tiles, group);
164→            const tileCount = positions ? positions.length : 1;
165→
166→            // T/L/5-line: track 3 intermediate (N+1) tiles conceptually created in merge chain
167→            if (isTLFormation || is5LineFormation) {
168→                const intermediateValue = group.value + 1;
169→                accumulateGoal(goalProgress, ctx.levelGoals, intermediateValue, 3);
170→            }
171→
172→            accumulateGoal(goalProgress, ctx.levelGoals, mergedValue, tileCount);
173→        });
174→
175→        // Process merges (mutates ctx.board)
176→        processMerges(ctx, matchGroups, ctx.isUserSwap);
177→
178→        // Apply gravity (mutates ctx.board, spawns new tiles)
179→        applyGravity(ctx);
180→
181→        cascades++;
182→        isFirstIteration = false;
183→        ctx.isUserSwap = false;
184→        ctx.lastSwapPosition = null;
185→    }
186→
187→    return {
188→        valid: true,
189→        newBoard: ctx.board,
190→        scoreDelta,
191→        goalProgress,
192→        cascades,
193→    };
194→}
