471→/**
472→ * Execute the board-level swap logic (pure: no DOM, no animation).
473→ * Mutates game.board and game state flags.
474→ * @returns {{ valid: boolean, hasMatch: boolean, hasFreeSwap: boolean, hasTeleport: boolean,
475→ *             isSwapPowerUp: boolean, isTeleportPowerUp: boolean, allowNonMatchingSwap: boolean }}
476→ *   An invalid or disallowed swap is indicated by `valid: false`.
477→ */
478→export function executeSwap(game, row1, col1, row2, col2) {
479→    const tile1 = game.board[row1][col1];
480→    const tile2 = game.board[row2][col2];
481→
482→    const isHorizontalSwap = row1 === row2;
483→    const isVerticalSwap = col1 === col2;
484→
485→    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
486→    const isFreeSwap2 = (isTileFreeSwapTile(tile2) || isTileStickyFreeSwapTile(tile2)) && !tile2.hasBeenSwapped;
487→    const isDirectionalFreeSwap1 =
488→        !tile1.hasBeenSwapped &&
489→        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
490→            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
491→    const isDirectionalFreeSwap2 =
492→        !tile2.hasBeenSwapped &&
493→        ((isTileFreeSwapHorizontalTile(tile2) && isHorizontalSwap) ||
494→            (isTileFreeSwapVerticalTile(tile2) && isVerticalSwap));
495→    const hasFreeSwap = isFreeSwap1 || isFreeSwap2 || isDirectionalFreeSwap1 || isDirectionalFreeSwap2;
496→    const hasTeleport = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
497→    const isSwapPowerUp = game.activePowerUp === "swap";
498→    const isTeleportPowerUp = game.activePowerUp === "teleport";
499→    const allowNonMatchingSwap = game.allowNonMatchingSwaps === true;
500→
501→    // Perform the board swap
502→    const temp = game.board[row1][col1];
503→    game.board[row1][col1] = game.board[row2][col2];
504→    game.board[row2][col2] = temp;
505→
506→    game.lastSwapPosition = { row: row2, col: col2, movedFrom: { row: row1, col: col1 } };
507→    game.isUserSwap = true;
508→
509→    const hasMatch = game.hasMatchesForSwap(row1, col1, row2, col2);
510→
511→    if (hasMatch || isSwapPowerUp || isTeleportPowerUp || hasFreeSwap || hasTeleport || allowNonMatchingSwap) {
512→        // Count the move
513→        if (!isSwapPowerUp && !isTeleportPowerUp && !hasFreeSwap && !hasTeleport) {
514→            game.movesUsed++;
515→        }
516→
517→        game.shouldDecrementCursedTimers = true;
518→        game.cursedTileCreatedThisTurn = {};
519→
520→        // Mark free swap tiles as used (tiles have been swapped, so tile1 is now at row2/col2)
521→        // Only the actively swapped tile (tile1) loses its special feature; the passively swapped tile (tile2) keeps it.
522→        if (hasFreeSwap) {
523→            if (isFreeSwap1 || isDirectionalFreeSwap1) game.board[row2][col2].hasBeenSwapped = true;
524→            if (isFreeSwap2 || isDirectionalFreeSwap2) game.board[row1][col1].hasBeenSwapped = true;
525→        }
526→        if (hasTeleport) {
527→            game.board[row2][col2].hasBeenSwapped = true;
528→        }
529→
530→        return {
531→            valid: true,
532→            hasMatch,
533→            hasFreeSwap,
534→            hasTeleport,
535→            isSwapPowerUp,
536→            isTeleportPowerUp,
537→            allowNonMatchingSwap,
538→        };
539→    } else {
540→        // Revert the swap
541→        game.board[row2][col2] = game.board[row1][col1];
542→        game.board[row1][col1] = temp;
543→        game.lastSwapPosition = null;
544→        game.isUserSwap = false;
545→        return {
546→            valid: false,
547→            hasMatch: false,
548→            hasFreeSwap,
549→            hasTeleport,
550→            isSwapPowerUp,
551→            isTeleportPowerUp,
552→            allowNonMatchingSwap,
553→        };
554→    }
555→}
