557→export function trySwap(game, row1, col1, row2, col2) {
558→    if (!game.gameActive) return;
559→
560→    // Tutorial validation - only allow defined swaps during tutorial
561→    if (isTutorialActive(game)) {
562→        if (!isValidTutorialSwap(game, row1, col1, row2, col2)) {
563→            game.animateRevert(row1, col1, row2, col2);
564→            return false;
565→        }
566→    }
567→
568→    // Prevent swapping if either tile is blocked or blocked with life
569→    // BLOCKED_MOVABLE tiles CAN be swapped
570→    if (
571→        isBlocked(game.board[row1][col1]) ||
572→        isBlocked(game.board[row2][col2]) ||
573→        isBlockedWithLife(game.board[row1][col1]) ||
574→        isBlockedWithLife(game.board[row2][col2])
575→    ) {
576→        return;
577→    }
578→
579→    const isAdjacentSwap = areAdjacent(row1, col1, row2, col2);
580→    const allowExtendedFreeSwap = !isAdjacentSwap && isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
581→    const allowTeleportSwap = !isAdjacentSwap && isTeleportSwapAllowed(game, row1, col1, row2, col2);
582→    const isPowerUpSwap = !isAdjacentSwap && game.activePowerUp === "teleport";
583→
584→    if (!isAdjacentSwap && !allowExtendedFreeSwap && !allowTeleportSwap && !isPowerUpSwap) {
585→        return false;
586→    }
587→
588→    // If animating, queue the swap to execute after animation completes
589→    if (game.animating) {
590→        game.interruptCascade = true;
591→        game.pendingSwap = {
592→            row1,
593→            col1,
594→            row2,
595→            col2,
596→            tile1: game.board[row1][col1],
597→            tile2: game.board[row2][col2],
598→        };
599→
600→        const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
601→        const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
602→        if (gem1) gem1.classList.add("pending-preview");
603→        if (gem2) gem2.classList.add("pending-preview");
604→
605→        return;
606→    }
607→
608→    // Execute board-level swap logic
609→    const result = executeSwap(game, row1, col1, row2, col2);
610→
611→    if (result.valid) {
612→        const { hasMatch, hasFreeSwap, hasTeleport, isSwapPowerUp, isTeleportPowerUp, allowNonMatchingSwap } = result;
613→
614→        game.updateMovesDisplay();
615→
616→        game.animateSwap(row1, col1, row2, col2, () => {
617→            game.renderBoard();
618→
619→            if (isTutorialActive(game)) {
620→                advanceTutorialStep(game);
621→            }
622→
623→            if (isSwapPowerUp) {
624→                game.consumePowerUp("swap");
625→                game.updatePowerUpButtons();
626→                track("power_up_used", {
627→                    level: game.currentLevel,
628→                    power_up_type: "swap",
629→                    remaining_moves: game.maxMoves - game.movesUsed,
630→                    uses_remaining: game.getTotalPowerUpCount("swap"),
631→                });
632→                game.deactivatePowerUp();
633→            }
634→
635→            if (isTeleportPowerUp) {
636→                game.consumePowerUp("teleport");
637→                game.updatePowerUpButtons();
638→                track("power_up_used", {
639→                    level: game.currentLevel,
640→                    power_up_type: "teleport",
641→                    remaining_moves: game.maxMoves - game.movesUsed,
642→                    uses_remaining: game.getTotalPowerUpCount("teleport"),
643→                });
644→                game.deactivatePowerUp();
645→            }
646→
647→            if (
648→                !hasMatch &&
649→                (allowNonMatchingSwap || hasTeleport || isTeleportPowerUp) &&
650→                !isSwapPowerUp &&
651→                !hasFreeSwap
652→            ) {
653→                game.lastSwapPosition = null;
654→                game.isUserSwap = false;
655→            }
656→
657→            document.querySelectorAll(".gem").forEach((gem) => {
658→                gem.classList.remove("dragging", "preview", "merge-preview", "unblock-preview");
659→            });
660→            game.selectedGem = null;
661→            game.isDragging = false;
662→            game.dragStartPos = null;
663→
664→            game.processMatches();
665→        });
666→
667→        return true;
668→    } else {
669→        game.animateRevert(row1, col1, row2, col2);
670→    }
671→}
