128→export function createRectangularBlockedWithMergeCount(rectId, anchor, width, height) {
129→    // Initialize cellMergeCounts dictionary
130→    const cellMergeCounts = {};
131→    for (let r = anchor.row; r < anchor.row + height; r++) {
132→        for (let c = anchor.col; c < anchor.col + width; c++) {
133→            cellMergeCounts[`${r}_${c}`] = 1; // Each cell needs 1 merge
134→        }
135→    }
136→
137→    return {
138→        type: TILE_TYPE.BLOCKED, // Use regular BLOCKED type
139→        value: null,
140→        immovable: true, // Always immovable
141→
142→        // Rectangular properties
143→        isRectangular: true,
144→        rectId: rectId,
145→        rectAnchor: anchor,
146→        rectWidth: width,
147→        rectHeight: height,
148→
149→        // Per-cell merge tracking
150→        cellMergeCounts: cellMergeCounts,
151→
152→        specialType: null,
153→        hasBeenSwapped: false,
154→    };
155→}
