237→// Convert internal value (1, 2, 3...) to display value (powers of 2)
238→export function getDisplayValue(internalValue) {
239→    // Powers of 2: 2^1=2, 2^2=4, 2^3=8, 2^4=16, etc.
240→    return Math.pow(2, internalValue);
