249→export function getUniqueTileValues(game) {
250→    const allValues = [];
251→    for (let r = 0; r < game.boardHeight; r++) {
252→        for (let c = 0; c < game.boardWidth; c++) {
253→            const tile = game.board[r][c];
254→            if (tile && tile.type === "normal") {
255→                const val = getTileValue(tile);
256→                if (!allValues.includes(val)) {
257→                    allValues.push(val);
258→                }
259→            }
260→        }
261→    }
262→    return allValues;
263→}
