265→/**
266→ * Find the best value for a joker tile to become, based on what creates valid matches.
267→ * Pure logic: temporarily mutates game.board but restores it before returning.
268→ */
269→export function findBestJokerValue(game, jokerRow, jokerCol, requireSwapConnection = false) {
270→    const originalTile = game.board[jokerRow][jokerCol];
271→
272→    if (!isJoker(originalTile)) {
273→        return null;
274→    }
275→
276→    const allValues = getUniqueTileValues(game);
277→    allValues.sort((a, b) => b - a);
278→
279→    for (const testValue of allValues) {
280→        game.board[jokerRow][jokerCol] = createTile(testValue);
281→
282→        const matches = game.findMatches();
283→
284→        const validMatch = matches.find((match) => {
285→            const includesJoker = match.tiles.some((tile) => tile.row === jokerRow && tile.col === jokerCol);
286→            if (!includesJoker) return false;
287→
288→            if (requireSwapConnection && game.lastSwapPosition) {
289→                const includesSourceTile = match.tiles.some(
290→                    (tile) => tile.row === game.lastSwapPosition.row && tile.col === game.lastSwapPosition.col,
291→                );
292→                if (!includesSourceTile) return false;
293→            }
294→
295→            const hasOtherJokers = match.tiles.some((tile) => {
296→                if (tile.row === jokerRow && tile.col === jokerCol) return false;
297→                return isJoker(game.board[tile.row][tile.col]);
298→            });
299→
300→            return !hasOtherJokers;
301→        });
302→
303→        if (validMatch) {
304→            game.board[jokerRow][jokerCol] = originalTile;
305→            return testValue;
306→        }
307→    }
308→
309→    game.board[jokerRow][jokerCol] = originalTile;
310→    return null;
311→}
