217→export function createMergedTiles(game, group, wasUserSwap = false) {
218→    const formationType = getFormationConfig(group.direction);
219→    let specialTileType = formationType ? game.specialTileConfig[formationType] : null;
220→
221→    // Calculate positions and value based on formation type
222→    const isTLFormation = group.direction === "T-formation" || group.direction === "L-formation";
223→    const is5LineFormation = group.direction === "line_5_horizontal" || group.direction === "line_5_vertical";
224→    const positions = isTLFormation ? [group.intersection] : calculateMiddlePositions(game, group.tiles, group);
225→    const valueIncrement = isTLFormation || is5LineFormation ? 2 : 1;
226→
227→    // When Super Streak is active and the setting is enabled,
228→    // replace Wildcard (joker) rewards with Wildcard Teleport
229→    if (is5LineFormation && game.superStrikeWildcardTeleport && game.superStreak >= SUPER_STREAK_THRESHOLD) {
230→        specialTileType = "wild_teleport";
231→    }
232→
233→    const newValue = group.value + valueIncrement;
234→
235→    // Check if sticky free swap should transfer (detected before tiles were cleared)
236→    // If so, and this was NOT a user swap, transfer the sticky free swap to the merged tile
237→    const hasStickyFreeSwap = group.hasStickyFreeSwap || false;
238→    const transferStickyFreeSwap = hasStickyFreeSwap && !wasUserSwap;
239→
240→    // Track intermediate values for formations that skip a level (T, L, 5-line)
241→    // When tiles of value N merge into 1 tile of value N+2, conceptually there's an intermediate step:
242→    // - T/L formation (5 tiles): 5 tiles → 3 tiles of N+1 → 1 tile of N+2
243→    // - 5-line formation (5 tiles): 5 tiles → 3 tiles of N+1 → 1 tile of N+2
244→    // So we track 3 creations of the intermediate value (N+1)
245→    if (isTLFormation || is5LineFormation) {
246→        const intermediateValue = group.value + 1;
247→        trackGoalProgress(game, intermediateValue, 3);
248→    }
249→
250→    // Handle special tile types
251→    if (specialTileType === "joker" || specialTileType === "wild_teleport") {
252→        // Joker and wild_teleport are special - they create JOKER type tiles, not normal tiles with properties
253→        const createSpecialTile = specialTileType === "wild_teleport" ? createWildTeleportTile : createJokerTile;
254→
255→        if (positions.length > 1) {
256→            const formationKey = group.direction.includes("block") ? "block_4" : "line_4";
257→            const specialPos = determineSpecialTilePosition(game, group, formationKey);
258→            const normalPos = positions.find((p) => p.row !== specialPos.row || p.col !== specialPos.col);
259→
260→            game.board[specialPos.row][specialPos.col] = createSpecialTile();
261→            game.board[normalPos.row][normalPos.col] = createTile(newValue, null, { transferStickyFreeSwap });
262→            trackGoalProgress(game, newValue, 1);
263→        } else {
264→            game.board[positions[0].row][positions[0].col] = createSpecialTile();
265→        }
266→    } else if (specialTileType && specialTileType !== "none") {
267→        // All other special tile types use the same pattern
268→        // For directional free swaps, determine the direction
269→        let options = { transferStickyFreeSwap };
270→
271→        if (specialTileType === "freeswap_horizontal" || specialTileType === "freeswap_vertical") {
272→            // Determine swap direction from lastSwapPosition
273→            let isHorizontal = false;
274→            if (game.lastSwapPosition && game.lastSwapPosition.movedFrom) {
275→                const fromRow = game.lastSwapPosition.movedFrom.row;
276→                const toRow = game.lastSwapPosition.row;
277→
278→                // If rows are the same, it's a horizontal swap (columns differ)
279→                isHorizontal = fromRow === toRow;
280→            }
281→            options.isHorizontal = isHorizontal;
282→        }
283→
284→        if (positions.length > 1) {
285→            // For 2-position formations (4-tile line/block), create one special tile and one normal tile
286→            const formationKey = group.direction.includes("block") ? "block_4" : "line_4";
287→            const specialPos = determineSpecialTilePosition(game, group, formationKey);
288→            const normalPos = positions.find((p) => p.row !== specialPos.row || p.col !== specialPos.col);
289→
290→            game.board[specialPos.row][specialPos.col] = createTile(newValue, specialTileType, options);
291→            game.board[normalPos.row][normalPos.col] = createTile(newValue, null, { transferStickyFreeSwap });
292→            trackGoalProgress(game, newValue, 2);
293→        } else {
294→            // For 1-position formations (T, L, 5-line), create one special tile
295→            game.board[positions[0].row][positions[0].col] = createTile(newValue, specialTileType, options);
296→            trackGoalProgress(game, newValue, 1);
297→        }
298→    } else {
299→        // No special tile - create normal tiles at all positions
300→        // However, if transferStickyFreeSwap is true, the merged tiles should inherit the sticky free swap ability
301→        positions.forEach((pos) => {
302→            game.board[pos.row][pos.col] = createTile(newValue, null, { transferStickyFreeSwap });
303→        });
304→        trackGoalProgress(game, newValue, positions.length);
305→    }
306→
307→    // After creating merged tiles, check if any should become cursed
308→    positions.forEach((pos) => {
309→        checkAndCreateCursedTile(game, newValue, pos);
310→    });
311→
312→    // Check if we need to shift tile levels based on the newly created value
313→    // This just sets a flag and the highest value reached, doesn't execute the shift yet
314→    game.checkAndShiftTileLevels(newValue);
315→
316→    // Check if creating this value should grant a power-up reward
317→    game.checkAndGrantPowerUpReward(newValue);
318→}
